module pcie_endpoint_controller(
    input wire clk,
    input wire rst_n,
    input wire req,
    output reg rsp
);

    reg rsp_d;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rsp <= 1'b0;
            rsp_d <= 1'b0;
        end else begin
            rsp_d <= req;
            rsp <= rsp_d;
        end
    end
endmodule
